let fileType =  { 
	"passport":"Pasaporte",
	"birth_certificate":"Certificado de nacimiento",
	"marriage_certificate":"Certificado de matrimonio",
	"licence":"Licencia",
	"parole": "Parole"
}



const LoadFileForCustomer  = ({ data,  confirm }) => {
	
	const frmNm = "birth_certificate"


	let flds = [
		
	]

	const [initialize, setInitialize] = useState(false);
	
	const [obs, set_obs] = useState(1);
	
	const updObs =  () => {
		set_obs(gen16CodeId())
	}



	
	useEffect(() => {
		if (!initialize) {
			
			setInitialize(true);
			updStore(frmNm, null);
			set_obs(gen16CodeId());

			setTimeout(() => {
				
				
				set_obs(gen16CodeId())
			}, 50);
			return () => {
				updStore(frmNm, null);
			}; 
		}
	});



	const updFrm = (f, v) => {
		let frm2 = getStore(frmNm) || {};
		frm2[f] = v;
		updStore(frmNm, frm2);
		set_obs(gen16CodeId())
	};



	const save  = async ()  => {

		
	}



	

	const close  = ()  => {
		data?.modalID && CloseModal({id:data?.modalID});
	}
	
	let validSv = compareJSON(flds,getStore(frmNm),getStore(frmNm + "_bck") )
	

	

	const updClient =  async(v) => {
		let cId = getStore(qryKClient())?.["clientNotaryId"];
		let bdyq2 = {...getStore(qryStore())?.upd_notary};
		bdyq2.params = {
			"clientNotaryId": cId
		}
		bdyq2.data2update = v;	

		const res = fetchEncryptStream(bdyq2);
		const td = await res;
		if (td && !td.error) {
			getById_notary(cId,updObs);
		}
	}





	const upload = async (file,fileName) => {
		getSignedUploadUrl(file,fileName, (url)=>{
			uploadSignedUrl(url,file,()=>updClient({imageUrlBCT: fileName}));
		});
	}




	

	const validateImage =    () => {

		let result =  getStore("preview_src");
		

		//var img = document.getElementById("face_id_recognition");
		//img.src = result;
		
		
		updStore( "image_2_template",null);
		updStore( "error_image",null);

		var i = new Image();	
				i.onload = function(){
					let dmzImg = {
						oh: i.height,
						ow: i.width,
						h: i.height,
						w: i.width
					}
					updStore( "preview_dmz",dmzImg);
					updObs();
				};
				if(result){
					i.src = result;
				}

	}



	const importCSV =  (event) => {
		const file = event.target.files[0];
		const reader = new FileReader();


		let fileName = gen16CodeId() +"_"+ file.name;
		// upload(file,fileName)

		reader.addEventListener(
			"load",
			() => {
				
				updStore( "preview_src",reader.result);
				validateImage();
			},
			false
		  );
		
		  if (file) {
			reader.readAsDataURL(file);
		  }
	}


	

	

	const openImage =  () => {
		let extTp = getExtFileType(getStore(qryKClient()).imageUrlBCT);
		handleFetchImage(getStore(qryKClient()).clientNotaryId,getStore(qryKClient()).imageUrlBCT, (v)=>openImageCb(v,extTp));
	}


	const openImageCb = async (v,ext) => {
		var blob = await b64toUrl(v, ext);
		window.open(blob)
	}



	


	const handleOnSel = (v) =>{
		updStore( "file_type_upload",v);
		updObs();
	}


	return(
		<div style={{
			maxHeight: "86vh",
			width: "820px",
			overflow: "auto",
			background: "var(--dark-800)",
			borderRadius: 13,
			padding: "10px 19px"
		}}>
			<div className="_dsplFlx ">
				<p className="form_title">
					Upload Documents
				</p>
				<div className="flexSpace"/>
				<div className="flexSpace"/>
				<div className="_dsplFlx "   style={{marginTop:12}}>
					<GrayUploadButton label={"Upload file"} onChange={importCSV}/>
					<div className="icon_image " onClick={openImage}>
						<Svg name={"extIcon"} color={"var(--partial-success)"}/>
					</div>
				</div>
				<div style={{margin: "9px 25px 0 5px"}}>
					<DropDwnPicker 
						lbl_empty={fileType[getStore("file_type_upload")] ||  "Tipo de Documento"} 
						list={[
							{label:"Pasaporte", id:"passport"},
							{label:"Certificado de nacimiento", id:"birth_certificate"},
							{label:"Certificado de matrimonio", id:"marriage_certificate"},
							{label:"Licencia", id:"licence"},
							{label:"Parole", id:"parole"},
						]} 
						onSelect={handleOnSel}
						background={"var(--dark-900)"}
						color={"var(--light-200)"}
						direction={"right"}
					/>
				</div>	
			</div>
		
		
			
			{getStore("preview_src")? 
			<div>
				<div style={{minHeight:260, marginTop: 30, width:"100%"}}  className="_dsplFlx ">
					<div className="flexSpace"/>
						<CardsHrm>
							<SVG_img
								image={getStore("preview_src")}
							/>
						</CardsHrm>
					<div className="flexSpace"/>
				</div>
				<div className="_dsplFlx ">
					<div className="flexSpace"/>
					<div className="card">
						{fileType[getStore("file_type_upload")] && getStore("preview_src")? 
						<GrayButton label={"Guardar"} clickHandler={save}/>
						:null}
					</div>
				</div>
			</div>
			:null}
			
		</div>
	)

}



